import java.io.IOException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String safeUserInput = sanitizeUserInput(userInput);

        String responseHtml = "<html><body>User Input: " + safeUserInput + "</body></html>";

        response.getWriter().write(responseHtml);
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input validation and sanitization here
        // Example: Using OWASP Java HTML Sanitizer to sanitize user input
        return org.owasp.html.Sanitizers.FORMATTING.and(org.owasp.html.Sanitizers.BLOCKS).sanitize(userInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
